import React, { useEffect, useState } from "react";
import { Table, Button, Space, Input, Tag, Tooltip } from "antd";
import { BiEdit, BiSearch, BiPackage } from "react-icons/bi";
import { AiFillDelete, AiOutlinePlus } from "react-icons/ai";
import { Link } from "react-router-dom";
import { useDispatch, useSelector } from "react-redux";
import {
  deletePackage,
  getPackages,
  resetState,
} from "../../features/package/packageSlicer";
import CustomModal from "../../components/CustomModal";

const PackageList = () => {
  const [open, setOpen] = useState(false);
  const [packageId, setPackageId] = useState("");
  const [searchText, setSearchText] = useState("");

  const showModal = (e) => {
    setOpen(true);
    setPackageId(e);
  };

  const hideModal = () => {
    setOpen(false);
  };

  const dispatch = useDispatch();

  useEffect(() => {
    dispatch(resetState());
    dispatch(getPackages());
  }, [dispatch]);

  const packageState = useSelector((state) => state.package.packages);

  const columns = [
    {
      title: "#ORDINAL",
      dataIndex: "key",
      render: (text) => (
        <span className="font-mono text-[10px] font-black text-gray-400">
          PKG-{text}
        </span>
      ),
      width: 100,
    },
    {
      title: "SUBSCRIPTION PLAN (NAME)",
      dataIndex: "name",
      render: (text) => (
        <Space size="small">
          <BiPackage className="text-gray-400" size={16} />
          <span className="font-black text-gray-900 tracking-tight uppercase text-xs">
            {text}
          </span>
        </Space>
      ),
      sorter: (a, b) => a.name.localeCompare(b.name),
    },
    {
      title: "TEMPORAL BIND (DURATION)",
      dataIndex: "duration",
      render: (months) => (
        <Tag
          color="blue"
          className="rounded-full font-bold border-none px-3 bg-blue-50 text-blue-600 text-[10px] uppercase"
        >
          {months} {months > 1 ? "MONTHS" : "MONTH"} CONTRACT
        </Tag>
      ),
      sorter: (a, b) => a.duration - b.duration,
    },
    {
      title: "FINANCIAL QUOTA (AMOUNT)",
      dataIndex: "amount",
      render: (val) => (
        <span className="font-black text-gray-900 tracking-tight text-xs">
          {val.toLocaleString()}{" "}
          <span className="text-[10px] text-gray-400">ETB</span>
        </span>
      ),
      sorter: (a, b) => a.amount - b.amount,
    },
    {
      title: "OPERATIONAL ACTIONS",
      dataIndex: "action",
      render: (_, record) => (
        <Space size="middle">
          <Link to={`/superAdmin/package/${record._id}`}>
            <Button
              type="text"
              icon={<BiEdit size={18} />}
              className="text-gray-400 hover:text-blue-600"
            />
          </Link>
          <Button
            type="text"
            danger
            icon={<AiFillDelete size={18} />}
            onClick={() => showModal(record._id)}
          />
        </Space>
      ),
    },
  ];

  const data =
    packageState
      ?.filter(
        (p) =>
          !searchText ||
          p.name.toLowerCase().includes(searchText.toLowerCase()),
      )
      .map((pkg, i) => ({
        ...pkg,
        key: i + 1,
      })) || [];

  const deletePackages = (id) => {
    dispatch(deletePackage(id));
    setOpen(false);
    setTimeout(() => {
      dispatch(getPackages());
    }, 100);
  };

  return (
    <div className="p-8 space-y-8 animate-in fade-in duration-500">
      {/* Header Section */}
      <div className="flex justify-between items-end border-b border-gray-100 pb-6">
        <div>
          <h1 className="text-3xl font-black text-gray-900 tracking-tight">
            Access Tiers Registry
          </h1>
          <p className="text-gray-500 font-medium tracking-tight">
            Subscription Lifecycle Control • Financial Scaling
          </p>
        </div>
        <div className="flex gap-4">
          <Input
            prefix={<BiSearch className="text-gray-400" />}
            placeholder="Search Access Tiers..."
            className="rounded-xl border-gray-100 w-64 h-11"
            onChange={(e) => setSearchText(e.target.value)}
          />
          <Link to="/superAdmin/package">
            <Button
              type="primary"
              size="large"
              className="bg-blue-600 flex items-center gap-2 rounded-xl font-bold"
            >
              <AiOutlinePlus /> Register Tier
            </Button>
          </Link>
        </div>
      </div>

      <div className="enterprise-card bg-white p-4">
        <Table
          columns={columns}
          dataSource={data}
          pagination={{
            pageSize: 12,
            showSizeChanger: true,
            className: "enterprise-pagination",
          }}
          className="enterprise-table super-modern-table"
          scroll={{ x: 1000 }}
        />
      </div>

      <CustomModal
        hideModal={hideModal}
        open={open}
        performAction={() => deletePackages(packageId)}
        title="Confirm Tier Termination"
        content="This action will permanently remove the subscription tier from the system registry. Active contracts may require manual migration."
      />
    </div>
  );
};

export default PackageList;
